sql:
SELECT COUNT(*) AS total_cases 
FROM cases 
WHERE created_by IN (SELECT user_id FROM users WHERE specialization = 'cardiology');

SELECT case_name, case_description
FROM cases
WHERE case_id = '1';

SELECT case_id, stage, AVG(points) AS AveragePoints
FROM diagnoses
GROUP BY case_id, stage;

SELECT AVG(users.years_of_experience) AS Average_Experience
FROM users
JOIN cases ON users.user_id = cases.created_by;

SELECT image_url, image_description 
FROM case_images 
WHERE case_id = '0';

external_knowledge:
- 'seasoned navigators' refers to users with over 5 years of experience;
- 'charted more than two courses' means users who have worked on more than two cases;
- 'exceptional precision' refers to a diagnosis accuracy greater than 90%;
- 'guiding their ships successfully through turbulent waters' metaphorically describes the process of making highly accurate diagnoses.

